import { PDFDocument, rgb, StandardFonts } from 'pdf-lib'

// Grand logo CSN bleu (JPEG)
const LOGO_B64 = ''

// Tampon CSN (JPEG)
const TAMPON_B64 = ''

export interface AttestationData {
  civilite:  string
  nom:       string
  prenom:    string
  montant:   string
  saison:    string
  dateJour:  string
}

/**
 * Formate le label de saison en "AAAA/AAAA"
 * Gère "2025-2026", "Saison 2025 2026", "2025/2026", etc.
 */
function formatSaison(label: string): string {
  const years = label.match(/\d{4}/g)
  if (years && years.length >= 2) return `${years[0]}/${years[1]}`
  return label
}

export async function generateAttestationPDF(data: AttestationData): Promise<Uint8Array> {
  const pdfDoc = await PDFDocument.create()
  const page   = pdfDoc.addPage([595, 842]) // A4

  const fontRegular = await pdfDoc.embedFont(StandardFonts.Helvetica)
  const fontBold    = await pdfDoc.embedFont(StandardFonts.HelveticaBold)

  const { width, height } = page.getSize()
  const navy  = rgb(0.1, 0.22, 0.36)
  const black = rgb(0, 0, 0)
  const gray  = rgb(0.4, 0.4, 0.4)

  // ── Logo couleur ──────────────────────────────────────────────────────────
  try {
    const logoBytes = Buffer.from(LOGO_B64, 'base64')
    const logoImg   = await pdfDoc.embedJpg(logoBytes)
    const logoW     = 80
    const logoH     = logoImg.height * (logoW / logoImg.width)
    // Centrer le logo verticalement par rapport au bloc texte (height-38 à height-78)
    const blockMid = height - 58
    page.drawImage(logoImg, {
      x: 45, y: blockMid - logoH / 2,
      width: logoW, height: logoH,
    })
  } catch (e) {
    console.error('[pdf] Logo embed error:', e)
  }

  // ── En-tête club ──────────────────────────────────────────────────────────
  const hx = 125
  page.drawText('CENTRE SUBAQUATIQUE NANTAIS', {
    x: hx, y: height - 38,
    size: 13, font: fontBold, color: navy,
  })
  page.drawText('F.F.E.S.S.M. N° 03-44-0034', {
    x: hx, y: height - 54,
    size: 9, font: fontRegular, color: gray,
  })
  page.drawText('3 Rue Conan Mériadec', {
    x: hx, y: height - 66,
    size: 9, font: fontRegular, color: gray,
  })
  page.drawText('44200 NANTES  –  02 40 48 12 62', {
    x: hx, y: height - 78,
    size: 9, font: fontRegular, color: gray,
  })

  // ── Ligne séparatrice ─────────────────────────────────────────────────────
  page.drawLine({
    start: { x: 45, y: height - 98 },
    end:   { x: width - 45, y: height - 98 },
    thickness: 0.5, color: navy,
  })

  // ── Centrage helper ───────────────────────────────────────────────────────
  function drawCentered(
    text: string, y: number,
    font = fontRegular, size = 12, color = black
  ) {
    const tw = font.widthOfTextAtSize(text, size)
    page.drawText(text, { x: (width - tw) / 2, y, size, font, color })
  }

  // ── Corps ─────────────────────────────────────────────────────────────────
  const saison  = formatSaison(data.saison)
  const bodyTop = height - 210

  drawCentered('Nous attestons que', bodyTop)

  const nomComplet = data.civilite
    ? `${data.civilite} ${data.prenom} ${data.nom},`
    : `${data.prenom} ${data.nom},`
  drawCentered(nomComplet, bodyTop - 42, fontBold, 13, navy)

  drawCentered("adhérent(e) de notre association", bodyTop - 84)
  drawCentered("a réglé sa cotisation",            bodyTop - 114)
  drawCentered(`pour la saison ${saison},`,        bodyTop - 144)
  drawCentered(`pour la somme de ${data.montant}`, bodyTop - 174, fontBold, 13, navy)

  // ── Date ──────────────────────────────────────────────────────────────────
  const dateTxt = `Fait à Nantes, le ${data.dateJour}`
  const dateW   = fontRegular.widthOfTextAtSize(dateTxt, 11)
  page.drawText(dateTxt, {
    x: width - 50 - dateW, y: bodyTop - 234,
    size: 11, font: fontRegular, color: black,
  })

  // ── Signatures ────────────────────────────────────────────────────────────
  const sigY = bodyTop - 300

  // Gauche : Président
  page.drawText('Le Président,', {
    x: 100, y: sigY, size: 11, font: fontRegular, color: black,
  })
  page.drawLine({
    start: { x: 100, y: sigY - 32 }, end: { x: 225, y: sigY - 32 },
    thickness: 0.4, color: rgb(0.75, 0.75, 0.75),
  })
  page.drawText('Stéphane Coué', {
    x: 100, y: sigY - 50, size: 11, font: fontBold, color: black,
  })

  // Droite : Secrétaire
  page.drawText('Le Secrétaire,', {
    x: width - 215, y: sigY, size: 11, font: fontRegular, color: black,
  })
  page.drawLine({
    start: { x: width - 215, y: sigY - 32 }, end: { x: width - 90, y: sigY - 32 },
    thickness: 0.4, color: rgb(0.75, 0.75, 0.75),
  })
  page.drawText('Yann Auber', {
    x: width - 215, y: sigY - 50, size: 11, font: fontBold, color: black,
  })

  // ── Tampon ────────────────────────────────────────────────────────────────
  try {
    const tamponBytes = Buffer.from(TAMPON_B64, 'base64')
    const tamponImg   = await pdfDoc.embedJpg(tamponBytes)
    // Positionner en bas à gauche, légèrement incliné n'est pas possible avec pdf-lib
    // On le place centré en bas, taille réduite
    const tW = 180
    const tH = tamponImg.height * (tW / tamponImg.width)
    page.drawImage(tamponImg, {
      x: (width - tW) / 2 - 80,
      y: sigY - 50 - tH - 20,
      width: tW, height: tH,
      opacity: 0.85,
    })
  } catch (e) {
    console.error('[pdf] Tampon embed error:', e)
  }

  return pdfDoc.save()
}
